import { TypeQuizQuestion } from "./quiz-types";
export const newQType2: TypeQuizQuestion[] = [
  // ── DIFFICULTY 1 (20 questions) ──
  { id: 551, type: 2, difficulty: 1 as 1|2|3|4|5, track1Day: 1, track2Day: 51, category: "Real-Life Scenarios", question: "A Type 2 arrives at a dinner party. What is their first instinct?", options: [{ letter: "A", text: "Check if the host needs help in the kitchen" }, { letter: "B", text: "Find a quiet corner to observe" }, { letter: "C", text: "Assess who the most important person in the room is" }, { letter: "D", text: "Start talking about themselves" }], answer: "A", explanation: "Twos automatically scan for others' needs. Their first impulse at any gathering is to offer help, making themselves indispensable through service." },
  { id: 552, type: 2, difficulty: 1 as 1|2|3|4|5, track1Day: 2, track2Day: 52, category: "Real-Life Scenarios", question: "A Type 2's friend cancels plans at the last minute. What is the Two's most likely internal reaction?", options: [{ letter: "A", text: "Relief — they can now have some alone time" }, { letter: "B", text: "Hurt feelings disguised as understanding: 'Of course, no problem!' while feeling rejected" }, { letter: "C", text: "Anger expressed directly: 'That's really inconsiderate'" }, { letter: "D", text: "Genuine indifference" }], answer: "B", explanation: "Twos mask their hurt with agreeableness. They'll say they understand while internally keeping score — the cancellation registers as evidence they're not valued enough." },
  { id: 553, type: 2, difficulty: 1 as 1|2|3|4|5, track1Day: 3, track2Day: 53, category: "Emotional Reactions", question: "When a Type 2 feels unappreciated, their first response is typically:", options: [{ letter: "A", text: "Withdraw and become silent" }, { letter: "B", text: "Give even more, hoping the increased effort will finally be noticed" }, { letter: "C", text: "Confront the person directly" }, { letter: "D", text: "Seek appreciation from a different person" }], answer: "B", explanation: "The Two's initial response to feeling unappreciated is to double down on giving. Their unconscious logic: 'If I just do more, they'll finally see how much I care and love me back.'" },
  { id: 554, type: 2, difficulty: 1 as 1|2|3|4|5, track1Day: 4, track2Day: 54, category: "Emotional Reactions", question: "How does a Type 2 typically react to receiving a gift or help from someone else?", options: [{ letter: "A", text: "They feel genuinely delighted and grateful" }, { letter: "B", text: "They feel uncomfortable and quickly try to reciprocate or deflect" }, { letter: "C", text: "They analyze whether the gift has hidden motives" }, { letter: "D", text: "They barely notice" }], answer: "B", explanation: "Twos are uncomfortable receiving because it disrupts their identity as the giver. Receiving puts them in a vulnerable position and implies they have needs — something they work hard to deny." },
  { id: 555, type: 2, difficulty: 1 as 1|2|3|4|5, track1Day: 5, track2Day: 55, category: "Type in Pop Culture", question: "Which Disney character best exemplifies Type 2 traits of self-sacrifice and people-pleasing?", options: [{ letter: "A", text: "Elsa from Frozen" }, { letter: "B", text: "Rapunzel from Tangled" }, { letter: "C", text: "Mrs. Potts from Beauty and the Beast" }, { letter: "D", text: "Merida from Brave" }], answer: "C", explanation: "Mrs. Potts is the quintessential Two: nurturing, warm, always serving others, motherly, and defining herself through caregiving. Her identity is completely wrapped up in tending to others' needs." },
  { id: 556, type: 2, difficulty: 1 as 1|2|3|4|5, track1Day: 6, track2Day: 56, category: "Type in Pop Culture", question: "In Friends, which character most displays Type 2 patterns of people-pleasing and needing to be needed?", options: [{ letter: "A", text: "Ross Geller" }, { letter: "B", text: "Monica Geller" }, { letter: "C", text: "Phoebe Buffay" }, { letter: "D", text: "Joey Tribbiani" }], answer: "B", explanation: "Monica's hosting, cooking, cleaning, and need to be the one everyone depends on are classic Two behaviors. Her competitiveness is often in service of being the best caretaker and hostess." },
  { id: 557, type: 2, difficulty: 1 as 1|2|3|4|5, track1Day: 7, track2Day: 57, category: "Quick Identification", question: "Which phrase is most characteristic of a Type 2?", options: [{ letter: "A", text: "I need some time alone to think" }, { letter: "B", text: "Let me know if there's anything I can do for you" }, { letter: "C", text: "What's the most efficient approach here?" }, { letter: "D", text: "I just want everyone to get along" }], answer: "B", explanation: "This reflexive offer of help is the Two's signature. It's often the first thing out of their mouth in any interaction, sometimes before the other person has even expressed a need." },
  { id: 558, type: 2, difficulty: 1 as 1|2|3|4|5, track1Day: 8, track2Day: 58, category: "Quick Identification", question: "Which behavior pattern most suggests someone is a Type 2?", options: [{ letter: "A", text: "Remembering everyone's birthday, dietary restrictions, and personal preferences" }, { letter: "B", text: "Keeping a detailed personal journal" }, { letter: "C", text: "Organizing their desk with perfect precision" }, { letter: "D", text: "Challenging authority when they disagree" }], answer: "A", explanation: "Twos invest enormous energy in tracking others' preferences and needs. This attention to detail about people is both genuine care and a strategy for making themselves indispensable." },
  { id: 559, type: 2, difficulty: 1 as 1|2|3|4|5, track1Day: 9, track2Day: 59, category: "Common Phrases", question: "Which internal monologue is most typical for a Type 2?", options: [{ letter: "A", text: "What's the right thing to do here?" }, { letter: "B", text: "What does this person need from me right now?" }, { letter: "C", text: "What's the most logical approach?" }, { letter: "D", text: "How can I stand out from the crowd?" }], answer: "B", explanation: "The Two's attention automatically flows outward to others' needs. This isn't a choice — it's a habitual pattern of attention that makes other people's emotional states the Two's primary data stream." },
  { id: 560, type: 2, difficulty: 1 as 1|2|3|4|5, track1Day: 10, track2Day: 60, category: "Common Phrases", question: "A Type 2 is most likely to say which of these after a long day of helping others?", options: [{ letter: "A", text: "I'm exhausted — I need to set better boundaries" }, { letter: "B", text: "It's fine, I love helping! I don't need anything" }, { letter: "C", text: "I'm done helping everyone else — time for me" }, { letter: "D", text: "I should analyze whether my help was effective" }], answer: "B", explanation: "Even when depleted, Twos deny their own needs. Admitting exhaustion from helping feels like admitting their giving has strings attached — which threatens their self-image as selfless." },
  { id: 561, type: 2, difficulty: 1 as 1|2|3|4|5, track1Day: 11, track2Day: 61, category: "Childhood Patterns", question: "What childhood experience is most formative for Type 2s?", options: [{ letter: "A", text: "Being encouraged to express all their emotions freely" }, { letter: "B", text: "Learning that love and attention came primarily through being helpful or pleasing others" }, { letter: "C", text: "Being left alone frequently and becoming self-sufficient" }, { letter: "D", text: "Being held to strict moral standards" }], answer: "B", explanation: "Twos learned early that their own needs weren't the priority — but they could secure love by meeting others' needs. This creates the adaptive strategy: 'I get love by giving, not by asking.'" },
  { id: 562, type: 2, difficulty: 1 as 1|2|3|4|5, track1Day: 12, track2Day: 62, category: "Childhood Patterns", question: "As children, Type 2s often developed the ability to:", options: [{ letter: "A", text: "Entertain themselves for hours alone" }, { letter: "B", text: "Read the emotional temperature of a room and adapt to meet others' needs" }, { letter: "C", text: "Follow complex rules and systems" }, { letter: "D", text: "Argue their point logically" }], answer: "B", explanation: "Young Twos develop remarkable emotional intelligence as a survival skill. They learn to sense what caregivers need and shape-shift accordingly — becoming the cheerful child, the caretaker, or the emotional support." },
  { id: 563, type: 2, difficulty: 1 as 1|2|3|4|5, track1Day: 13, track2Day: 63, category: "Communication Style", question: "How does a Type 2 typically apologize?", options: [{ letter: "A", text: "With a brief, logical acknowledgment of the error" }, { letter: "B", text: "With emotional warmth, physical touch, and offers to make it up to the person" }, { letter: "C", text: "By deflecting blame onto circumstances" }, { letter: "D", text: "By avoiding the topic entirely" }], answer: "B", explanation: "Twos apologize relationally — they focus on restoring the emotional connection rather than analyzing the error. They might bring gifts, offer hugs, or go out of their way to demonstrate care." },
  { id: 564, type: 2, difficulty: 1 as 1|2|3|4|5, track1Day: 14, track2Day: 64, category: "Communication Style", question: "In group conversations, a Type 2 most often:", options: [{ letter: "A", text: "Steers the topic toward their own interests" }, { letter: "B", text: "Notices who seems left out and draws them into the conversation" }, { letter: "C", text: "Stays quiet and observes" }, { letter: "D", text: "Debates ideas and challenges others' viewpoints" }], answer: "B", explanation: "Twos are emotional radar systems in group settings. They automatically track who's comfortable, who's being excluded, and who needs acknowledgment — then intervene to include everyone." },
  { id: 565, type: 2, difficulty: 1 as 1|2|3|4|5, track1Day: 15, track2Day: 65, category: "Real-Life Scenarios", question: "A Type 2 is sick in bed. What is their biggest struggle?", options: [{ letter: "A", text: "Boredom from inactivity" }, { letter: "B", text: "Allowing others to take care of them without feeling guilty" }, { letter: "C", text: "Missing work deadlines" }, { letter: "D", text: "Being alone with their thoughts" }], answer: "B", explanation: "Being cared for is deeply uncomfortable for Twos because it reverses their identity. They may try to help their caretakers even while sick, or feel guilty that they're 'burdening' others with their needs." },
  { id: 566, type: 2, difficulty: 1 as 1|2|3|4|5, track1Day: 16, track2Day: 66, category: "Emotional Reactions", question: "When a Type 2's help is rejected, they feel:", options: [{ letter: "A", text: "Relieved of responsibility" }, { letter: "B", text: "Personally wounded, as if their very identity was rejected" }, { letter: "C", text: "Motivated to try a different approach" }, { letter: "D", text: "Intellectually curious about why" }], answer: "B", explanation: "For Twos, their help IS their identity. Rejecting their help feels like rejecting them as a person. This is why refused assistance can trigger surprisingly intense emotional reactions." },
  { id: 567, type: 2, difficulty: 1 as 1|2|3|4|5, track1Day: 17, track2Day: 67, category: "Quick Identification", question: "At a restaurant, a Type 2 is most likely to:", options: [{ letter: "A", text: "Order quickly and efficiently" }, { letter: "B", text: "Help everyone else decide what to order before choosing for themselves" }, { letter: "C", text: "Order the most unique item on the menu" }, { letter: "D", text: "Calculate the bill split in advance" }], answer: "B", explanation: "The Two attends to everyone else's experience first: suggesting dishes based on their preferences, making sure dietary needs are met, and only then — almost as an afterthought — choosing for themselves." },
  { id: 568, type: 2, difficulty: 1 as 1|2|3|4|5, track1Day: 18, track2Day: 68, category: "Common Phrases", question: "Which of these statements reveals the Two's hidden need for reciprocity?", options: [{ letter: "A", text: "I don't need anything in return" }, { letter: "B", text: "After everything I've done for you..." }, { letter: "C", text: "I just like being helpful" }, { letter: "D", text: "It's no trouble at all" }], answer: "B", explanation: "This phrase emerges when the Two's unspoken contract — 'I give, you love me back' — is broken. It reveals that the giving was never entirely selfless; there was always an implicit expectation of reciprocity." },
  { id: 569, type: 2, difficulty: 1 as 1|2|3|4|5, track1Day: 19, track2Day: 69, category: "Childhood Patterns", question: "Type 2 children often report feeling like:", options: [{ letter: "A", text: "The smartest kid in the class" }, { letter: "B", text: "A small parent — responsible for their caregivers' emotional well-being" }, { letter: "C", text: "An outsider who never fit in" }, { letter: "D", text: "A natural leader among their peers" }], answer: "B", explanation: "Many Twos describe childhood 'parentification' — taking on the role of emotional caretaker for their parents. They learned to suppress their own needs and focus on managing their family's emotional climate." },
  { id: 570, type: 2, difficulty: 1 as 1|2|3|4|5, track1Day: 20, track2Day: 70, category: "Communication Style", question: "A Type 2's texting style typically includes:", options: [{ letter: "A", text: "Short, efficient messages" }, { letter: "B", text: "Warm check-ins, heart emojis, and unprompted offers of support" }, { letter: "C", text: "Long analytical paragraphs" }, { letter: "D", text: "Rare responses — they're not big texters" }], answer: "B", explanation: "Twos communicate warmth and availability through constant small gestures: 'thinking of you' texts, checking in during hard times, and liberally using warm emojis. Their phone is a tool for maintaining connection." },
  // ── DIFFICULTY 2 (20 questions) ──
  { id: 571, type: 2, difficulty: 2 as 1|2|3|4|5, track1Day: 21, track2Day: 71, category: "Relationship Dynamics", question: "In romantic relationships, Type 2s are most at risk of:", options: [{ letter: "A", text: "Being emotionally unavailable" }, { letter: "B", text: "Losing themselves by over-adapting to their partner's needs and preferences" }, { letter: "C", text: "Being too independent and self-focused" }, { letter: "D", text: "Intellectualizing their emotions" }], answer: "B", explanation: "Twos shape-shift to match their partner's desires, often losing touch with their own preferences, opinions, and needs. They may not realize this until the relationship ends and they can't remember who they are." },
  { id: 572, type: 2, difficulty: 2 as 1|2|3|4|5, track1Day: 22, track2Day: 72, category: "Relationship Dynamics", question: "Why do Type 2s often attract Type 5 partners?", options: [{ letter: "A", text: "Random chance" }, { letter: "B", text: "The Two's warmth draws out the Five's hidden desire for connection, while the Five's boundaries challenge the Two's engulfing tendencies" }, { letter: "C", text: "They have identical values" }, { letter: "D", text: "They don't — these types are incompatible" }], answer: "B", explanation: "The 2-5 pairing creates a push-pull dynamic: the Two offers the emotional warmth the Five secretly craves, while the Five's need for space forces the Two to confront their own neediness. It's challenging but growth-producing." },
  { id: 573, type: 2, difficulty: 2 as 1|2|3|4|5, track1Day: 23, track2Day: 73, category: "Defense Mechanisms", question: "What is the primary defense mechanism of Type 2?", options: [{ letter: "A", text: "Intellectualization" }, { letter: "B", text: "Repression — pushing their own needs out of conscious awareness" }, { letter: "C", text: "Projection" }, { letter: "D", text: "Reaction formation" }], answer: "B", explanation: "Repression is the Two's core defense: they literally lose awareness of their own needs, desires, and feelings. They're not choosing to ignore their needs — the needs are pushed below the threshold of consciousness." },
  { id: 574, type: 2, difficulty: 2 as 1|2|3|4|5, track1Day: 24, track2Day: 74, category: "Defense Mechanisms", question: "How does the Two's pride serve as a defense mechanism?", options: [{ letter: "A", text: "It doesn't — pride is a positive trait" }, { letter: "B", text: "Pride in being needed protects them from the devastating possibility that they are not lovable for who they are" }, { letter: "C", text: "It helps them achieve career goals" }, { letter: "D", text: "It keeps them motivated" }], answer: "B", explanation: "The Two's pride ('I'm the one everyone depends on') is a defense against their deepest fear: that they're inherently unlovable. If they're essential, they can never be abandoned — pride makes them feel irreplaceable." },
  { id: 575, type: 2, difficulty: 2 as 1|2|3|4|5, track1Day: 25, track2Day: 75, category: "Conflict Style", question: "How does a Type 2 typically initiate conflict?", options: [{ letter: "A", text: "With direct confrontation" }, { letter: "B", text: "Indirectly — through guilt-tripping, emotional withdrawal, or reminding others of past favors" }, { letter: "C", text: "Through logical argumentation" }, { letter: "D", text: "They never initiate conflict" }], answer: "B", explanation: "Twos rarely confront directly because it threatens their 'nice' image. Instead, they use emotional leverage: sighs, hurt looks, references to sacrifices made, or strategic withdrawal of warmth to make others feel guilty." },
  { id: 576, type: 2, difficulty: 2 as 1|2|3|4|5, track1Day: 26, track2Day: 76, category: "Conflict Style", question: "When a Type 2 finally explodes in anger after long suppression, what typically happens?", options: [{ letter: "A", text: "They calmly express their frustration" }, { letter: "B", text: "They unleash a catalog of unreciprocated favors and unacknowledged sacrifices" }, { letter: "C", text: "They become physically aggressive" }, { letter: "D", text: "They immediately apologize and retreat" }], answer: "B", explanation: "The Two's anger explosion reveals the secret ledger they've been keeping. Suddenly every unreturned favor, every ignored sacrifice, every taken-for-granted kindness comes flooding out — shocking everyone who thought the Two had no needs." },
  { id: 577, type: 2, difficulty: 2 as 1|2|3|4|5, track1Day: 27, track2Day: 77, category: "Shadow Work", question: "What is the primary shadow of Type 2?", options: [{ letter: "A", text: "Their secret desire for power and control" }, { letter: "B", text: "Their own neediness, selfishness, and manipulative use of giving to control others" }, { letter: "C", text: "Their intellectual ambitions" }, { letter: "D", text: "Their competitive nature" }], answer: "B", explanation: "The Two's shadow contains everything they project onto others: neediness, selfishness, and the desire to receive. Their giving often has an unconscious manipulative element — creating debt and dependency to ensure they're never abandoned." },
  { id: 578, type: 2, difficulty: 2 as 1|2|3|4|5, track1Day: 28, track2Day: 78, category: "Shadow Work", question: "Why is the concept of 'covert contracts' particularly relevant to Type 2?", options: [{ letter: "A", text: "Twos are contract lawyers" }, { letter: "B", text: "Twos unconsciously create unspoken agreements: 'I give to you; you owe me love' — without the other person ever agreeing" }, { letter: "C", text: "Twos have explicit expectations that they communicate clearly" }, { letter: "D", text: "This concept doesn't apply to Twos" }], answer: "B", explanation: "Covert contracts are the Two's hidden operating system. They give freely (seemingly) but secretly expect reciprocal love, appreciation, or loyalty. When the unspoken contract is broken, the Two feels betrayed — but the other person never knew the contract existed." },
  { id: 579, type: 2, difficulty: 2 as 1|2|3|4|5, track1Day: 29, track2Day: 79, category: "Parenting Style", question: "How does a Type 2 parent typically show love?", options: [{ letter: "A", text: "Through structured routines and clear rules" }, { letter: "B", text: "Through anticipating needs, physical affection, and sometimes over-involvement in children's lives" }, { letter: "C", text: "Through intellectual engagement and teaching" }, { letter: "D", text: "Through encouraging independence and risk-taking" }], answer: "B", explanation: "Two parents express love through nurturing actions: cooking favorites, remembering details, offering comfort. The risk is over-involvement — the parent may struggle to let children develop independence because they need to be needed." },
  { id: 580, type: 2, difficulty: 2 as 1|2|3|4|5, track1Day: 30, track2Day: 80, category: "Parenting Style", question: "What is the biggest risk of Type 2 parenting?", options: [{ letter: "A", text: "Being too strict" }, { letter: "B", text: "Creating children who feel obligated to meet the parent's emotional needs" }, { letter: "C", text: "Neglecting children due to work" }, { letter: "D", text: "Being too permissive about academics" }], answer: "B", explanation: "Two parents can inadvertently create a role reversal where children feel responsible for the parent's happiness. The child learns that love means caretaking, potentially creating another generation of Twos or codependents." },
  { id: 581, type: 2, difficulty: 2 as 1|2|3|4|5, track1Day: 31, track2Day: 81, category: "Attachment Style", question: "Which attachment style is most commonly associated with Type 2?", options: [{ letter: "A", text: "Dismissive-avoidant" }, { letter: "B", text: "Anxious-preoccupied" }, { letter: "C", text: "Secure" }, { letter: "D", text: "Fearful-avoidant" }], answer: "B", explanation: "Twos commonly display anxious attachment: preoccupied with relationships, seeking closeness, sensitive to rejection, and using people-pleasing to maintain connection. Their self-worth depends heavily on relational feedback." },
  { id: 582, type: 2, difficulty: 2 as 1|2|3|4|5, track1Day: 32, track2Day: 82, category: "Somatic Patterns", question: "Where do Type 2s typically hold emotional energy in their body?", options: [{ letter: "A", text: "In their head and forehead" }, { letter: "B", text: "In their chest, arms, and hands — the instruments of reaching out and embracing" }, { letter: "C", text: "In their legs and feet" }, { letter: "D", text: "In their lower back" }], answer: "B", explanation: "As a heart center type, Twos carry energy in their chest (heart), arms (reaching toward others), and hands (serving, touching, giving). Physical tension often manifests as tightness in the upper body, especially when giving is unreciprocated." },
  { id: 583, type: 2, difficulty: 2 as 1|2|3|4|5, track1Day: 33, track2Day: 83, category: "Somatic Patterns", question: "What physical symptom do burned-out Type 2s commonly experience?", options: [{ letter: "A", text: "Insomnia from racing thoughts" }, { letter: "B", text: "Exhaustion, adrenal fatigue, and physical collapse after extended over-giving" }, { letter: "C", text: "Headaches from concentration" }, { letter: "D", text: "Digestive issues from anxiety" }], answer: "B", explanation: "Twos push past physical limits to serve others, ignoring fatigue signals. Eventually the body forces rest through collapse, illness, or burnout — the physical consequences of chronically prioritizing others over self." },
  { id: 584, type: 2, difficulty: 2 as 1|2|3|4|5, track1Day: 34, track2Day: 84, category: "Coping Under Stress", question: "What does healthy stress management look like for a Type 2?", options: [{ letter: "A", text: "Helping even more people to feel better" }, { letter: "B", text: "Setting boundaries and identifying their own needs before attending to others" }, { letter: "C", text: "Isolating completely" }, { letter: "D", text: "Channeling stress into work achievement" }], answer: "B", explanation: "Healthy Two coping involves the counterintuitive act of turning attention inward: 'What do I need right now?' This simple question is revolutionary for a type that has been trained to never ask it." },
  { id: 585, type: 2, difficulty: 2 as 1|2|3|4|5, track1Day: 35, track2Day: 85, category: "Coping Under Stress", question: "When a Type 2 moves to their stress point (Type 8), they become:", options: [{ letter: "A", text: "Withdrawn and detached" }, { letter: "B", text: "Aggressive, domineering, and demanding — insisting others acknowledge their contributions" }, { letter: "C", text: "Anxious and indecisive" }, { letter: "D", text: "Scattered and impulsive" }], answer: "B", explanation: "Under stress, the sweet Two channels Eight energy: they become confrontational, territorial, and demanding. The suppressed anger from years of unreciprocated giving erupts as 'I've given everything and gotten nothing back!'" },
  { id: 586, type: 2, difficulty: 2 as 1|2|3|4|5, track1Day: 36, track2Day: 86, category: "Relationship Dynamics", question: "What does a Type 2 need most from their partner?", options: [{ letter: "A", text: "Intellectual stimulation" }, { letter: "B", text: "To be loved for who they are, not what they do for others" }, { letter: "C", text: "Exciting adventures and novelty" }, { letter: "D", text: "A partner who needs them completely" }], answer: "B", explanation: "The Two's deepest need is to be loved unconditionally — not as the helper, caretaker, or fixer, but simply as a person. A partner who says 'I love you even when you're not doing anything for me' touches the Two's core wound." },
  { id: 587, type: 2, difficulty: 2 as 1|2|3|4|5, track1Day: 37, track2Day: 87, category: "Shadow Work", question: "What is 'emotional manipulation' in the context of unhealthy Type 2 behavior?", options: [{ letter: "A", text: "Deliberately lying to control others" }, { letter: "B", text: "Using kindness, favors, and emotional intimacy to create obligation and dependency" }, { letter: "C", text: "Threatening others to get their way" }, { letter: "D", text: "Twos are never manipulative" }], answer: "B", explanation: "Unhealthy Two manipulation is subtle: it works through generosity rather than threats. By making themselves indispensable and creating emotional debt, they bind people to them — often without conscious awareness of the pattern." },
  { id: 588, type: 2, difficulty: 2 as 1|2|3|4|5, track1Day: 38, track2Day: 88, category: "Defense Mechanisms", question: "The concept of 'emotional fusion' is particularly relevant to Type 2. What does it mean?", options: [{ letter: "A", text: "Being very empathetic" }, { letter: "B", text: "Losing the boundary between one's own feelings and others' feelings, so the Two can't tell the difference" }, { letter: "C", text: "Fusing different ideas together creatively" }, { letter: "D", text: "A healthy level of emotional connection" }], answer: "B", explanation: "Emotional fusion goes beyond empathy — the Two literally experiences others' emotions as their own. When someone near them is sad, the Two feels sad. This makes it impossible to identify their OWN emotional state independently." },
  { id: 589, type: 2, difficulty: 2 as 1|2|3|4|5, track1Day: 39, track2Day: 89, category: "Conflict Style", question: "How does a 2w1 handle conflict differently from a 2w3?", options: [{ letter: "A", text: "2w1 uses moral authority ('I sacrificed and you should too'); 2w3 uses charm and image management" }, { letter: "B", text: "They are identical in conflict" }, { letter: "C", text: "2w1 is aggressive; 2w3 is passive" }, { letter: "D", text: "2w1 avoids all conflict; 2w3 seeks it out" }], answer: "A", explanation: "The One wing gives 2w1 a moralistic edge in conflict — they frame their grievance as a matter of fairness and duty. The Three wing gives 2w3 a more image-conscious approach — they use charm, charisma, or social leverage." },
  { id: 590, type: 2, difficulty: 2 as 1|2|3|4|5, track1Day: 40, track2Day: 90, category: "Attachment Style", question: "How does the Two's anxious attachment manifest in friendships?", options: [{ letter: "A", text: "They have very few close friends" }, { letter: "B", text: "They over-invest in friendships, feel hurt by unanswered texts, and keep mental score of reciprocity" }, { letter: "C", text: "They're completely secure and easy-going" }, { letter: "D", text: "They maintain superficial relationships only" }], answer: "B", explanation: "Two friendships often have an unspoken intensity: the Two tracks who initiated contact last, who remembered birthdays, and who showed up when needed. This mental ledger creates anxiety when the 'balance' feels unequal." },
  // ── DIFFICULTY 3 (20 questions) ──
  { id: 591, type: 2, difficulty: 3 as 1|2|3|4|5, track1Day: 41, track2Day: 91, category: "Workplace Archetypes", question: "What leadership style is most natural for a Type 2?", options: [{ letter: "A", text: "Autocratic and directive" }, { letter: "B", text: "Servant leadership — leading by supporting, mentoring, and building personal relationships with team members" }, { letter: "C", text: "Data-driven and analytical" }, { letter: "D", text: "Hands-off delegation" }], answer: "B", explanation: "Two leaders excel through personal connection. They know each team member's name, family situation, and career goals. Their power comes from loyalty and genuine care — people follow them because they feel seen." },
  { id: 592, type: 2, difficulty: 3 as 1|2|3|4|5, track1Day: 42, track2Day: 92, category: "Workplace Archetypes", question: "What is a Type 2 manager's biggest blind spot?", options: [{ letter: "A", text: "Not caring enough about people" }, { letter: "B", text: "Playing favorites, difficulty giving tough feedback, and taking it personally when employees leave" }, { letter: "C", text: "Being too focused on data over people" }, { letter: "D", text: "Micromanaging tasks" }], answer: "B", explanation: "Two managers struggle with professional boundaries. They may favor team members who show the most appreciation, avoid giving negative feedback to preserve relationships, and feel personally betrayed when valued employees resign." },
  { id: 593, type: 2, difficulty: 3 as 1|2|3|4|5, track1Day: 43, track2Day: 93, category: "Spiritual Traditions", question: "What is the virtue that Type 2 develops through growth?", options: [{ letter: "A", text: "Courage" }, { letter: "B", text: "Humility — the genuine recognition of their own needs and limitations" }, { letter: "C", text: "Serenity" }, { letter: "D", text: "Sobriety" }], answer: "B", explanation: "Humility for the Two doesn't mean self-deprecation — it means honestly acknowledging their own needs, limitations, and motivations. True humility allows the Two to receive as naturally as they give." },
  { id: 594, type: 2, difficulty: 3 as 1|2|3|4|5, track1Day: 44, track2Day: 94, category: "Spiritual Traditions", question: "What is the 'Holy Idea' that Type 2 has lost touch with?", options: [{ letter: "A", text: "Holy Will — trusting that they will be taken care of without having to earn it" }, { letter: "B", text: "Holy Truth" }, { letter: "C", text: "Holy Perfection" }, { letter: "D", text: "Holy Omniscience" }], answer: "A", explanation: "Holy Will (or Holy Freedom) is the Two's lost knowing: that love and care will come without having to manipulate, earn, or maneuver for it. Reconnecting with this truth dissolves the compulsive need to give in order to receive." },
  { id: 595, type: 2, difficulty: 3 as 1|2|3|4|5, track1Day: 45, track2Day: 95, category: "Enneagram x MBTI", question: "Which MBTI types are most commonly found among Enneagram Type 2s?", options: [{ letter: "A", text: "INTJ and INTP" }, { letter: "B", text: "ESFJ and ENFJ" }, { letter: "C", text: "ISTP and ESTP" }, { letter: "D", text: "INFP and ISFP" }], answer: "B", explanation: "ESFJ and ENFJ share the Two's extraverted feeling (Fe) orientation: a natural focus on others' emotional needs, social harmony, and relational attunement. Both types prioritize connection and community care." },
  { id: 596, type: 2, difficulty: 3 as 1|2|3|4|5, track1Day: 46, track2Day: 96, category: "Enneagram x MBTI", question: "How might a Type 2 with INFP cognitive functions present differently from a typical Two?", options: [{ letter: "A", text: "They would be identical" }, { letter: "B", text: "More introspective and selective about who they help, with deeper but fewer relationships" }, { letter: "C", text: "They wouldn't be a Type 2" }, { letter: "D", text: "More extraverted and people-focused" }], answer: "B", explanation: "An INFP Two has Fi (introverted feeling) rather than Fe. This creates a more selective helper: they give deeply to chosen individuals aligned with their values rather than broadly to everyone. They're still motivated by love but express it more privately." },
  { id: 597, type: 2, difficulty: 3 as 1|2|3|4|5, track1Day: 47, track2Day: 97, category: "Instinct x Wing Combos", question: "How does a sexual (sx) Type 2w3 typically present?", options: [{ letter: "A", text: "As a quiet, humble helper" }, { letter: "B", text: "As a charismatic, seductive person who uses personal magnetism to draw people close" }, { letter: "C", text: "As a strict rule-follower" }, { letter: "D", text: "As a withdrawn intellectual" }], answer: "B", explanation: "The sx 2w3 combines the Two's desire to be loved with the Three's charm and the sexual instinct's intensity. This creates someone who uses personal magnetism, attractiveness, and emotional seduction to become the center of someone's world." },
  { id: 598, type: 2, difficulty: 3 as 1|2|3|4|5, track1Day: 48, track2Day: 98, category: "Instinct x Wing Combos", question: "How does a self-preservation (sp) 2w1 differ from a social (so) 2w3?", options: [{ letter: "A", text: "sp 2w1 helps through practical acts of service in the home; so 2w3 helps through building networks and social influence" }, { letter: "B", text: "They are the same" }, { letter: "C", text: "sp 2w1 is more extraverted; so 2w3 is more introverted" }, { letter: "D", text: "sp 2w1 doesn't help at all" }], answer: "A", explanation: "The sp 2w1 expresses care through concrete, domestic acts — cooking, cleaning, running errands. The so 2w3 expresses care through social positioning — connecting people, building community, and leveraging their network for others' benefit." },
  { id: 599, type: 2, difficulty: 3 as 1|2|3|4|5, track1Day: 49, track2Day: 99, category: "Tritype Deep Dives", question: "What characterizes the 2-7-9 tritype?", options: [{ letter: "A", text: "The 'tough love' archetype — direct and confrontational" }, { letter: "B", text: "The 'sunshine' archetype — relentlessly positive, warm, and conflict-avoidant" }, { letter: "C", text: "The 'dark intellectual' — withdrawn and analytical" }, { letter: "D", text: "The 'rebel leader' — defiant and independent" }], answer: "B", explanation: "The 2-7-9 tritype combines the Two's warmth, the Seven's optimism, and the Nine's peacefulness. This creates the ultimate 'positive vibes' person — endlessly kind and upbeat, but potentially avoidant of difficult emotions." },
  { id: 600, type: 2, difficulty: 3 as 1|2|3|4|5, track1Day: 50, track2Day: 100, category: "Tritype Deep Dives", question: "How does the 2-8-6 tritype manifest?", options: [{ letter: "A", text: "As a gentle, passive helper" }, { letter: "B", text: "As a protective 'mama bear' who fiercely defends their people and demands loyalty" }, { letter: "C", text: "As a detached observer" }, { letter: "D", text: "As a free-spirited adventurer" }], answer: "B", explanation: "The 2-8-6 combines the Two's nurturing with the Eight's protectiveness and the Six's loyalty. This creates a powerful caretaker who will fight for their loved ones and expects unwavering loyalty in return." },
  { id: 601, type: 2, difficulty: 3 as 1|2|3|4|5, track1Day: 51, track2Day: 1, category: "Growth Practices", question: "Which practice most effectively supports Type 2 growth?", options: [{ letter: "A", text: "Volunteering more to strengthen their giving muscles" }, { letter: "B", text: "Daily check-ins asking 'What do I need right now?' before attending to others" }, { letter: "C", text: "Reading self-help books about how to help others better" }, { letter: "D", text: "Spending more time in social situations" }], answer: "B", explanation: "The revolutionary practice for Twos is simply asking themselves what THEY need. This basic question is surprisingly difficult because the Two's attention habitually flows outward. Regular practice rebuilds the atrophied 'self-care' muscle." },
  { id: 602, type: 2, difficulty: 3 as 1|2|3|4|5, track1Day: 52, track2Day: 2, category: "Growth Practices", question: "Why is learning to say 'no' considered transformative for Type 2s?", options: [{ letter: "A", text: "It makes them more efficient" }, { letter: "B", text: "It proves they can be loved without earning it through service, dismantling their core fear" }, { letter: "C", text: "It saves time" }, { letter: "D", text: "It doesn't help Twos" }], answer: "B", explanation: "Each genuine 'no' is an experiment: 'Will they still love me if I don't say yes?' When the answer is yes, it provides experiential evidence that the Two's lovability doesn't depend on compliance — directly healing their core wound." },
  { id: 603, type: 2, difficulty: 3 as 1|2|3|4|5, track1Day: 53, track2Day: 3, category: "Naranjo's Character Types", question: "What is the 'fixation' of Type 2 in Naranjo's framework?", options: [{ letter: "A", text: "Resentment" }, { letter: "B", text: "Flattery — the habitual strategy of winning love through making others feel special" }, { letter: "C", text: "Vanity" }, { letter: "D", text: "Cowardice" }], answer: "B", explanation: "Naranjo identified flattery as the Two's cognitive fixation: the automatic mental strategy of focusing on others' positive qualities, making them feel valued, and thereby securing a special place in their affections." },
  { id: 604, type: 2, difficulty: 3 as 1|2|3|4|5, track1Day: 54, track2Day: 4, category: "Naranjo's Character Types", question: "Naranjo described the Two as having 'histrionic' tendencies. What does this mean in the Enneagram context?", options: [{ letter: "A", text: "They are dramatic and attention-seeking" }, { letter: "B", text: "They use emotional expressiveness and seductiveness to draw others close and secure attachment" }, { letter: "C", text: "They have a clinical disorder" }, { letter: "D", text: "They are dishonest" }], answer: "B", explanation: "Naranjo connected the Two to the histrionic character structure: emotional expressiveness, relational intensity, and the use of warmth and seductiveness to create bonds. This isn't pathological — it's the Two's adaptive strategy for securing love." },
  { id: 605, type: 2, difficulty: 3 as 1|2|3|4|5, track1Day: 55, track2Day: 5, category: "Workplace Archetypes", question: "A Type 2 employee is most likely to burn out from:", options: [{ letter: "A", text: "Boredom with repetitive tasks" }, { letter: "B", text: "Taking on everyone's emotional burdens plus their own workload, unable to say no" }, { letter: "C", text: "Lack of intellectual challenge" }, { letter: "D", text: "Conflict with management" }], answer: "B", explanation: "Two burnout is unique: it comes from being the office therapist, emotional support system, and extra-task volunteer simultaneously. They won't say no because each 'yes' reinforces their identity as indispensable." },
  { id: 606, type: 2, difficulty: 3 as 1|2|3|4|5, track1Day: 56, track2Day: 6, category: "Instinct x Wing Combos", question: "Which instinct/wing combination makes a Type 2 look most like a Type 4?", options: [{ letter: "A", text: "so 2w3" }, { letter: "B", text: "sx 2w1" }, { letter: "C", text: "sp 2w3" }, { letter: "D", text: "so 2w1" }], answer: "B", explanation: "The sx 2w1 combines sexual intensity with the One wing's introspection and moral seriousness. This creates a more emotionally complex Two who can appear moody, intense, and focused on deep one-on-one connection — resembling a Four." },
  { id: 607, type: 2, difficulty: 3 as 1|2|3|4|5, track1Day: 57, track2Day: 7, category: "Growth Practices", question: "Why does Type 2 growth involve moving toward Type 4 qualities?", options: [{ letter: "A", text: "Because Fours are more successful" }, { letter: "B", text: "Because connecting with their own emotional depth and authentic self-expression counters the Two's self-abandonment" }, { letter: "C", text: "Because Fours need the Two's help" }, { letter: "D", text: "It doesn't — Twos should avoid Four behavior" }], answer: "B", explanation: "Integration to Four means the Two finally turns attention inward: discovering their own emotional landscape, creative expression, and authentic identity separate from their role as helper. They learn that their inner world is worth exploring." },
  { id: 608, type: 2, difficulty: 3 as 1|2|3|4|5, track1Day: 58, track2Day: 8, category: "Enneagram x MBTI", question: "A Type 2 with Ti (introverted thinking) as an auxiliary function would most likely:", options: [{ letter: "A", text: "Stop caring about people" }, { letter: "B", text: "Analyze and systematize their helping — creating structured programs or frameworks for supporting others" }, { letter: "C", text: "Not be a Type 2" }, { letter: "D", text: "Be identical to any other Two" }], answer: "B", explanation: "A Two with Ti (like an ENFJ with developed Ti) channels their relational drive through analytical frameworks. They might design support systems, create mentoring programs, or write about relational dynamics — structured helping." },
  { id: 609, type: 2, difficulty: 3 as 1|2|3|4|5, track1Day: 59, track2Day: 9, category: "Spiritual Traditions", question: "Which spiritual practice most supports the Two's transformation?", options: [{ letter: "A", text: "Service projects and volunteering" }, { letter: "B", text: "Solitude and self-inquiry — learning to be alone and still without serving anyone" }, { letter: "C", text: "Group prayer and community worship" }, { letter: "D", text: "Studying theology" }], answer: "B", explanation: "Solitude is the Two's transformative practice because it removes the external 'audience' for their giving. Alone with themselves, Twos must finally face the question they've avoided: 'Who am I when I'm not helping?'" },
  { id: 610, type: 2, difficulty: 3 as 1|2|3|4|5, track1Day: 60, track2Day: 10, category: "Naranjo's Character Types", question: "Naranjo described the Two as being prone to 'false generosity.' What distinguishes false from genuine generosity?", options: [{ letter: "A", text: "The amount given" }, { letter: "B", text: "False generosity has unconscious strings attached; genuine generosity expects nothing in return" }, { letter: "C", text: "False generosity is smaller; genuine is larger" }, { letter: "D", text: "There is no difference" }], answer: "B", explanation: "Naranjo distinguished between the Two's compulsive giving (driven by the need for love) and genuine generosity (an overflow of fullness). The former creates debt; the latter creates freedom. Growth means shifting from the first to the second." },
  // ── DIFFICULTY 4 (20 questions) ──
  { id: 611, type: 2, difficulty: 4 as 1|2|3|4|5, track1Day: 61, track2Day: 11, category: "Panel Wisdom", question: "On an Enneagram panel, a Two says: 'I realized I was keeping score without knowing it. When I stopped expecting reciprocity, I actually felt free for the first time.' This illustrates:", options: [{ letter: "A", text: "The Two abandoning their caring nature" }, { letter: "B", text: "The Two becoming conscious of their covert contracts and releasing them" }, { letter: "C", text: "A mistyped Two" }, { letter: "D", text: "Unhealthy detachment" }], answer: "B", explanation: "This is a pivotal Two insight: recognizing the hidden transactional nature of their giving. When the unconscious ledger becomes conscious, the Two can choose genuine generosity — giving without the binding strings of expectation." },
  { id: 612, type: 2, difficulty: 4 as 1|2|3|4|5, track1Day: 62, track2Day: 12, category: "Panel Wisdom", question: "A panelist shares: 'The scariest thing I ever did was tell someone I needed help. I was sure they'd think less of me.' This reveals:", options: [{ letter: "A", text: "Social anxiety" }, { letter: "B", text: "The Two's core belief that having needs makes them unlovable and their vulnerability in asking" }, { letter: "C", text: "Introversion" }, { letter: "D", text: "Low self-esteem unrelated to type" }], answer: "B", explanation: "For a Two, asking for help is the ultimate vulnerability because it contradicts their identity as the giver. The fear that having needs makes them less lovable is the core wound — and consciously asking despite that fear is profound growth." },
  { id: 613, type: 2, difficulty: 4 as 1|2|3|4|5, track1Day: 63, track2Day: 13, category: "Ichazo Fixations", question: "In Ichazo's system, what is the 'Trap' of Type 2?", options: [{ letter: "A", text: "Efficiency" }, { letter: "B", text: "Freedom — the belief that if they just give enough, they'll be free from their neediness" }, { letter: "C", text: "Perfection" }, { letter: "D", text: "Security" }], answer: "B", explanation: "Ichazo identified Freedom as the Two's trap: the fantasy that enough giving will finally liberate them from their own needs. But the more they give to avoid their needs, the more dependent they become on others' appreciation." },
  { id: 614, type: 2, difficulty: 4 as 1|2|3|4|5, track1Day: 64, track2Day: 14, category: "Ichazo Fixations", question: "What is the Holy Idea that Type 2 needs to reconnect with?", options: [{ letter: "A", text: "Holy Perfection" }, { letter: "B", text: "Holy Will — the trust that the universe provides care without the Two needing to manipulate for it" }, { letter: "C", text: "Holy Truth" }, { letter: "D", text: "Holy Origin" }], answer: "B", explanation: "Holy Will means trusting that love and support exist in the fabric of reality, not just in transactions. When the Two reconnects with this knowing, they can relax their compulsive giving because they trust they'll be cared for naturally." },
  { id: 615, type: 2, difficulty: 4 as 1|2|3|4|5, track1Day: 65, track2Day: 15, category: "Object Relations Deep", question: "In the Hornevian groups, Type 2 belongs to the 'Compliant' group. How does this manifest differently from Type 1's compliance?", options: [{ letter: "A", text: "It manifests identically" }, { letter: "B", text: "Twos comply by moving toward people through emotional seduction and service; Ones comply through duty and moral correctness" }, { letter: "C", text: "Twos are not compliant" }, { letter: "D", text: "The difference is only in intensity" }], answer: "B", explanation: "Both types 'move toward' people (Karen Horney's term), but the Two does so through warmth, giving, and emotional attunement, while the One does so through responsibility and moral effort. Same direction, different currency." },
  { id: 616, type: 2, difficulty: 4 as 1|2|3|4|5, track1Day: 66, track2Day: 16, category: "Object Relations Deep", question: "How does the Two's 'rejection' object relation manifest?", options: [{ letter: "A", text: "They reject others frequently" }, { letter: "B", text: "They unconsciously reject their own needs while becoming attuned to others', creating a pattern of self-neglect" }, { letter: "C", text: "They fear rejection more than other types" }, { letter: "D", text: "They don't have a rejection pattern" }], answer: "B", explanation: "The Two belongs to the 'rejection' group (with 5 and 8). They reject their own needs, Fives reject emotional demands, and Eights reject vulnerability. The Two's self-rejection is the most hidden because it looks like selflessness." },
  { id: 617, type: 2, difficulty: 4 as 1|2|3|4|5, track1Day: 67, track2Day: 17, category: "Counter-Instinctual Combos", question: "The self-preservation Two is considered the 'countertype.' Why?", options: [{ letter: "A", text: "They don't help others" }, { letter: "B", text: "Instead of overtly giving to others, they give to themselves through cultivating relationships with powerful people who can meet their needs" }, { letter: "C", text: "They are the most generous Two" }, { letter: "D", text: "They look like Type 9s" }], answer: "B", explanation: "The sp Two is the countertype because they reverse the typical Two pattern: instead of obviously giving to get love, they attract support by being cute, charming, or childlike — earning care through endearment rather than service." },
  { id: 618, type: 2, difficulty: 4 as 1|2|3|4|5, track1Day: 68, track2Day: 18, category: "Counter-Instinctual Combos", question: "Naranjo described the sp Two as having a quality of 'privilege.' What does this mean?", options: [{ letter: "A", text: "They come from wealthy backgrounds" }, { letter: "B", text: "They feel entitled to care and support from others — the hidden neediness that other Twos disguise through giving" }, { letter: "C", text: "They are privileged in society" }, { letter: "D", text: "They have special abilities" }], answer: "B", explanation: "The sp Two's 'privilege' means they more openly expect to be taken care of — which is actually the honest expression of what ALL Twos secretly want. Other Two subtypes disguise this need through giving; the sp Two is more direct." },
  { id: 619, type: 2, difficulty: 4 as 1|2|3|4|5, track1Day: 69, track2Day: 19, category: "Differential Diagnosis", question: "Both Type 2 and Type 9 are accommodating and conflict-avoidant. How do you tell them apart?", options: [{ letter: "A", text: "You can't" }, { letter: "B", text: "Twos accommodate to secure love (heart center); Nines accommodate to maintain peace (body center). Twos track who they've helped; Nines genuinely forget their preferences" }, { letter: "C", text: "Twos are always extraverted; Nines are always introverted" }, { letter: "D", text: "Only age differentiates them" }], answer: "B", explanation: "The key difference is motivation and awareness. Twos knowingly suppress their needs to win love (and track the sacrifices). Nines genuinely lose touch with their needs — they're not suppressing them, they've actually merged with others' agendas." },
  { id: 620, type: 2, difficulty: 4 as 1|2|3|4|5, track1Day: 70, track2Day: 20, category: "Differential Diagnosis", question: "A person is warm, gives a lot, and seems selfless. How do you distinguish a healthy Type 2 from a healthy Type 9 with a 2 fix?", options: [{ letter: "A", text: "The Two's giving has more energetic intentionality; the Nine's giving is more diffuse and easygoing" }, { letter: "B", text: "They are indistinguishable" }, { letter: "C", text: "Nines never help others" }, { letter: "D", text: "Twos are always more generous" }], answer: "A", explanation: "The Two gives with direction and energy — there's an active quality to it, a reaching toward the other person. The Nine with a 2 fix gives more passively — it flows naturally without the Two's underlying urgency to be needed." },
  { id: 621, type: 2, difficulty: 4 as 1|2|3|4|5, track1Day: 71, track2Day: 21, category: "Historical Enneagram", question: "Which Enneagram author emphasized the Two's connection to 'the image of love' versus actual love?", options: [{ letter: "A", text: "Oscar Ichazo" }, { letter: "B", text: "Don Riso and Russ Hudson — noting that Twos often confuse the performance of love with love itself" }, { letter: "C", text: "Helen Palmer" }, { letter: "D", text: "G.I. Gurdjieff" }], answer: "B", explanation: "Riso and Hudson articulated that the Two's core confusion is between love-as-performance and love-as-being. The Two works so hard at looking loving that they may lose contact with the genuine experience of love — both giving and receiving it." },
  { id: 622, type: 2, difficulty: 4 as 1|2|3|4|5, track1Day: 72, track2Day: 22, category: "Historical Enneagram", question: "Helen Palmer's 'attention practice' for Type 2 involves:", options: [{ letter: "A", text: "Paying more attention to others' needs" }, { letter: "B", text: "Noticing when their attention automatically moves toward others and consciously redirecting it inward" }, { letter: "C", text: "Ignoring other people" }, { letter: "D", text: "Studying Enneagram theory" }], answer: "B", explanation: "Palmer taught Twos to observe the moment their attention shifts from self to other. This 'catch the shift' practice builds awareness of the automatic pattern, creating a choice point where the Two can stay with their own experience." },
  { id: 623, type: 2, difficulty: 4 as 1|2|3|4|5, track1Day: 73, track2Day: 23, category: "Integration/Disintegration Chains", question: "When Type 2 moves to their stress point (Type 8), what does the progression look like?", options: [{ letter: "A", text: "Increased generosity → exhaustion → withdrawal" }, { letter: "B", text: "Intensified helping → resentment build-up → explosive anger and demands for recognition" }, { letter: "C", text: "Anxiety → overthinking → paralysis" }, { letter: "D", text: "Distraction → scattered energy → collapse" }], answer: "B", explanation: "The Two's path to Eight follows a predictable arc: give more, feel unappreciated, build resentment, then finally explode with the Eight's forcefulness. The eruption is shocking to others because it contradicts the Two's sweet persona." },
  { id: 624, type: 2, difficulty: 4 as 1|2|3|4|5, track1Day: 74, track2Day: 24, category: "Integration/Disintegration Chains", question: "What does healthy integration to Type 4 look like for a Two?", options: [{ letter: "A", text: "Becoming depressed and withdrawn" }, { letter: "B", text: "Developing authentic self-expression, emotional depth, and the ability to sit with their own feelings without redirecting to others" }, { letter: "C", text: "Becoming artistic but impractical" }, { letter: "D", text: "Losing interest in people" }], answer: "B", explanation: "Healthy Four integration gives the Two an inner life. They develop genuine emotional depth, creative self-expression, and the radical ability to simply feel their own feelings without immediately converting them into service for others." },
  { id: 625, type: 2, difficulty: 4 as 1|2|3|4|5, track1Day: 75, track2Day: 25, category: "Ichazo Fixations", question: "How does the Two's passion of pride interact with their fixation of flattery?", options: [{ letter: "A", text: "They are unrelated" }, { letter: "B", text: "Pride inflates the Two's sense of indispensability; flattery is the mental strategy used to maintain that position by making others feel special" }, { letter: "C", text: "Flattery causes pride" }, { letter: "D", text: "Pride prevents flattery" }], answer: "B", explanation: "Pride (emotional) and flattery (cognitive) form a self-reinforcing loop: pride tells the Two they're uniquely important to others, and flattery is the strategy that makes it so. The Two flatters to create dependency, which feeds their pride." },
  { id: 626, type: 2, difficulty: 4 as 1|2|3|4|5, track1Day: 76, track2Day: 26, category: "Panel Wisdom", question: "A Two panelist reveals: 'I finally realized that my helping was a form of control. If I'm the one everyone depends on, I can never be left.' This shows:", options: [{ letter: "A", text: "That the Two is secretly a Type 8" }, { letter: "B", text: "Deep self-awareness about how the Two's giving strategy is ultimately about preventing abandonment" }, { letter: "C", text: "A bitter Two who has lost their caring nature" }, { letter: "D", text: "Misunderstanding of their type" }], answer: "B", explanation: "This is one of the most profound Two realizations: that their apparent selflessness has a self-serving core — preventing abandonment. This insight isn't cause for shame but for liberation: once seen, the pattern can be released." },
  { id: 627, type: 2, difficulty: 4 as 1|2|3|4|5, track1Day: 77, track2Day: 27, category: "Object Relations Deep", question: "In Sandra Maitri's work, what essential quality has the Two lost contact with?", options: [{ letter: "A", text: "Essential Strength" }, { letter: "B", text: "The quality of 'Merging Gold' — unconditional love that exists without earning it" }, { letter: "C", text: "Essential Joy" }, { letter: "D", text: "Essential Peace" }], answer: "B", explanation: "Maitri identifies the Two's lost essential quality as the experience of unconditional love — love that simply IS, without needing to be earned through giving. The Two's compulsive helping is a substitute for this direct experience of being loved." },
  { id: 628, type: 2, difficulty: 4 as 1|2|3|4|5, track1Day: 78, track2Day: 28, category: "Counter-Instinctual Combos", question: "How does the social Two (so2) express their helping differently from the sexual Two (sx2)?", options: [{ letter: "A", text: "so2 helps through group influence, mentoring, and being the 'power behind the throne'; sx2 helps through intense one-on-one devotion" }, { letter: "B", text: "They are identical" }, { letter: "C", text: "so2 is less helpful" }, { letter: "D", text: "sx2 is less emotional" }], answer: "A", explanation: "The so2 is the 'social strategist' — they help by connecting with important people and wielding social influence. The sx2 is the 'intimate devotee' — they pour everything into one person, becoming that person's world." },
  { id: 629, type: 2, difficulty: 4 as 1|2|3|4|5, track1Day: 79, track2Day: 29, category: "Differential Diagnosis", question: "Both Type 2 and Type 3 are heart center types concerned with image. The key distinction is:", options: [{ letter: "A", text: "Twos are more successful" }, { letter: "B", text: "Twos want to be seen as loving and indispensable; Threes want to be seen as successful and admirable" }, { letter: "C", text: "They have identical motivations" }, { letter: "D", text: "Threes are warmer" }], answer: "B", explanation: "Both types manage their image but seek different reflections. The Two wants to see 'I am loved and needed' in others' eyes. The Three wants to see 'I am impressive and successful.' Different currencies, same heart-center strategy." },
  { id: 630, type: 2, difficulty: 4 as 1|2|3|4|5, track1Day: 80, track2Day: 30, category: "Historical Enneagram", question: "In the Riso-Hudson system, at which Level of Development does the Two begin to use giving as manipulation?", options: [{ letter: "A", text: "Level 1 (healthiest)" }, { letter: "B", text: "Level 5-6 (average to unhealthy) — when the Two becomes possessive and begins using giving to create obligation" }, { letter: "C", text: "Level 9 (most unhealthy)" }, { letter: "D", text: "All levels" }], answer: "B", explanation: "At Levels 1-4, the Two's giving is increasingly genuine. At Level 5, the Two begins to 'hover and intrude,' and by Level 6, giving becomes a strategy to create indebtedness. This transition from genuine to manipulative giving is gradual and often unconscious." },
  // ── DIFFICULTY 5 (20 questions) ──
  { id: 631, type: 2, difficulty: 5 as 1|2|3|4|5, track1Day: 81, track2Day: 31, category: "Panel Wisdom", question: "An advanced Two on a panel says: 'True humility for me wasn't thinking less of myself — it was finally admitting I have needs at all.' This reflects:", options: [{ letter: "A", text: "Low self-esteem" }, { letter: "B", text: "The Two's virtue of humility as genuine self-honesty rather than self-deprecation" }, { letter: "C", text: "False modesty" }, { letter: "D", text: "A mistyped Two" }], answer: "B", explanation: "This captures the exact nature of Two humility: not becoming smaller, but becoming honest. Admitting 'I have needs' is revolutionary for a type that built their entire identity on being the one without needs." },
  { id: 632, type: 2, difficulty: 5 as 1|2|3|4|5, track1Day: 82, track2Day: 32, category: "Ichazo Fixations", question: "Ichazo described Type 2's 'Ego-Flattery' as a structural distortion. How does this differ from simply being complimentary?", options: [{ letter: "A", text: "It is more genuine" }, { letter: "B", text: "Ego-Flattery is a perceptual filter that automatically selects what others want to hear, creating a false bridge of connection based on emotional manipulation rather than truth" }, { letter: "C", text: "There is no difference" }, { letter: "D", text: "It only applies to famous people" }], answer: "B", explanation: "Ego-Flattery is not a conscious choice but a structural pattern of perception. The Two's ego automatically identifies what will make others feel good and produces it — creating genuine-feeling but strategically oriented emotional connections." },
  { id: 633, type: 2, difficulty: 5 as 1|2|3|4|5, track1Day: 83, track2Day: 33, category: "Object Relations Deep", question: "Karen Horney's concept of 'moving toward people' in Type 2 involves what she called the 'self-effacing solution.' How does this manifest?", options: [{ letter: "A", text: "The Two becomes invisible" }, { letter: "B", text: "The Two erases their own needs and identity to become what others need, gaining safety through indispensability" }, { letter: "C", text: "The Two becomes more assertive" }, { letter: "D", text: "The Two withdraws from people" }], answer: "B", explanation: "Horney's self-effacing solution describes the Two's core strategy: solve the problem of potential rejection by making yourself so essential that others can't afford to lose you. The self is sacrificed on the altar of connection." },
  { id: 634, type: 2, difficulty: 5 as 1|2|3|4|5, track1Day: 84, track2Day: 34, category: "Counter-Instinctual Combos", question: "According to Beatrice Chestnut, the sp Two's 'privilege' manifests most clearly as:", options: [{ letter: "A", text: "Financial privilege" }, { letter: "B", text: "An unconscious sense that they deserve care without having to overtly earn it — being cute, charming, or childlike to attract nurturing" }, { letter: "C", text: "Social status" }, { letter: "D", text: "Educational advantages" }], answer: "B", explanation: "Chestnut describes the sp Two as the least overtly helpful Two. Instead of giving to earn love, they attract it through a childlike appeal — an unspoken expectation that they should be taken care of because of who they are, not what they do." },
  { id: 635, type: 2, difficulty: 5 as 1|2|3|4|5, track1Day: 85, track2Day: 35, category: "Differential Diagnosis", question: "In clinical settings, the Two's pattern of over-giving and boundary issues can be confused with:", options: [{ letter: "A", text: "Narcissistic personality disorder" }, { letter: "B", text: "Codependency — but the Enneagram Two is a motivational pattern (driven by pride), while codependency is a relational pattern that can affect any type" }, { letter: "C", text: "Autism spectrum" }, { letter: "D", text: "ADHD" }], answer: "B", explanation: "While Two patterns overlap heavily with codependency, they're distinct frameworks. A Two can be codependent, but not all codependents are Twos. The Two's pattern is specifically driven by pride and the fear of being unlovable — the Enneagram adds motivational depth." },
  { id: 636, type: 2, difficulty: 5 as 1|2|3|4|5, track1Day: 86, track2Day: 36, category: "Integration/Disintegration Chains", question: "In the full disintegration chain, a very unhealthy Two (2→8→5) might exhibit:", options: [{ letter: "A", text: "Increased generosity" }, { letter: "B", text: "Explosive demands for acknowledgment (8), followed by bitter withdrawal and paranoid isolation (5)" }, { letter: "C", text: "Gentle self-care" }, { letter: "D", text: "Spiritual growth" }], answer: "B", explanation: "The deep disintegration 2→8→5 shows the Two exploding with Eight rage ('After everything I've done!'), then, when that fails, collapsing into Five withdrawal — becoming isolated, bitter, and convinced nobody will ever truly love them." },
  { id: 637, type: 2, difficulty: 5 as 1|2|3|4|5, track1Day: 87, track2Day: 37, category: "Historical Enneagram", question: "At Riso-Hudson Level 9 (most pathological), the Type 2 becomes:", options: [{ letter: "A", text: "A generous saint" }, { letter: "B", text: "A coercive, manipulative figure who uses past generosity as blackmail, potentially becoming a 'psychosomatic invalid' to force caregiving" }, { letter: "C", text: "A detached loner" }, { letter: "D", text: "An aggressive leader" }], answer: "B", explanation: "At Level 9, the Two's strategy has completely inverted: instead of giving to receive, they now demand care through guilt, illness, or emotional coercion. The 'generous' person has become a tyrant of emotional debt." },
  { id: 638, type: 2, difficulty: 5 as 1|2|3|4|5, track1Day: 88, track2Day: 38, category: "Panel Wisdom", question: "A Two describes their awakening: 'I discovered I didn't know what I liked for dinner. Not what my husband likes, not what the kids want — what I actually enjoy. I had no idea.' This reveals:", options: [{ letter: "A", text: "That they have no preferences" }, { letter: "B", text: "How thoroughly the Two's repression defense has erased their own desires — even basic preferences are unknown" }, { letter: "C", text: "Poor memory" }, { letter: "D", text: "A food-related issue unrelated to type" }], answer: "B", explanation: "This powerful example shows the depth of the Two's self-abandonment. Repression isn't just about big needs — it extends to basic preferences. The Two has been so focused outward that simple questions about their own desires draw a blank." },
  { id: 639, type: 2, difficulty: 5 as 1|2|3|4|5, track1Day: 89, track2Day: 39, category: "Ichazo Fixations", question: "In Ichazo's 'Enneagon of Avoidances,' what does Type 2 avoid?", options: [{ letter: "A", text: "Conflict" }, { letter: "B", text: "Acknowledging their own needs — the Two avoids their own neediness at all costs" }, { letter: "C", text: "Being alone" }, { letter: "D", text: "Hard work" }], answer: "B", explanation: "The Two's fundamental avoidance is their own neediness. Admitting 'I need' threatens their identity as the giver and risks confirming their worst fear: that they are, at core, just as needy as everyone else — maybe more so." },
  { id: 640, type: 2, difficulty: 5 as 1|2|3|4|5, track1Day: 90, track2Day: 40, category: "Object Relations Deep", question: "How does the Two's 'rejection triad' membership interact with their heart-center location?", options: [{ letter: "A", text: "They don't interact" }, { letter: "B", text: "The Two rejects their own emotional needs (rejection triad) while being hyper-attuned to others' emotions (heart center), creating a split between self-awareness and other-awareness" }, { letter: "C", text: "They're identical concepts" }, { letter: "D", text: "The heart center prevents rejection" }], answer: "B", explanation: "This dual membership creates the Two's central paradox: they are emotional experts about everyone except themselves. Their heart-center gifts give them extraordinary empathy for others while the rejection stance blinds them to their own emotional reality." },
  { id: 641, type: 2, difficulty: 5 as 1|2|3|4|5, track1Day: 91, track2Day: 41, category: "Counter-Instinctual Combos", question: "How does the so/sx Two stack compare to the sx/sp Two stack in terms of relational strategy?", options: [{ letter: "A", text: "so/sx builds broad social networks of dependency and uses sexual charm selectively; sx/sp pours into one relationship totally and needs material security from that bond" }, { letter: "B", text: "They are identical" }, { letter: "C", text: "so/sx is more introverted" }, { letter: "D", text: "sx/sp is less emotional" }], answer: "A", explanation: "The so/sx Two is the networker-seducer: they build wide circles of people who depend on them, using selective charm to maintain key relationships. The sx/sp Two is the devoted partner: intensely focused on one person and needing that bond to provide both emotional and material security." },
  { id: 642, type: 2, difficulty: 5 as 1|2|3|4|5, track1Day: 92, track2Day: 42, category: "Differential Diagnosis", question: "A client presents with intense focus on one person, emotional dependency, and fear of abandonment. This could be Type 2 or Borderline PD. The Enneagram-informed distinction is:", options: [{ letter: "A", text: "There is no distinction" }, { letter: "B", text: "The Two pattern is ego-syntonic (feels natural and right to the Two) and is specifically organized around pride, while BPD involves ego-dystonic distress and identity instability not specific to the pride pattern" }, { letter: "C", text: "Twos never have clinical issues" }, { letter: "D", text: "BPD is always more severe" }], answer: "B", explanation: "Enneagram Two is a motivational structure centered on pride and the need to give. BPD is a clinical condition with specific criteria including identity disturbance and self-harm. They can co-occur but aren't the same. The Two's pattern feels like 'who I am'; BPD feels distressing." },
  { id: 643, type: 2, difficulty: 5 as 1|2|3|4|5, track1Day: 93, track2Day: 43, category: "Integration/Disintegration Chains", question: "What does the Two's 'second integration' (2→4→1) look like in practice?", options: [{ letter: "A", text: "Becoming self-centered and rigid" }, { letter: "B", text: "Gaining authentic self-awareness (4), then developing personal integrity and inner standards not dependent on others' approval (1)" }, { letter: "C", text: "Becoming depressed and perfectionistic" }, { letter: "D", text: "Losing interest in relationships" }], answer: "B", explanation: "The extended integration 2→4→1 takes the Two from self-abandonment through authentic self-discovery (4) to genuine inner principles (1). The result is a person who knows who they are and what they stand for, independent of others' needs." },
  { id: 644, type: 2, difficulty: 5 as 1|2|3|4|5, track1Day: 94, track2Day: 44, category: "Naranjo's Character Types", question: "Naranjo connected the Two's character structure to which psychoanalytic concept?", options: [{ letter: "A", text: "The narcissistic character" }, { letter: "B", text: "The 'oral-receptive' character who compensates for unmet dependency needs by becoming the giver" }, { letter: "C", text: "The obsessive character" }, { letter: "D", text: "The schizoid character" }], answer: "B", explanation: "Naranjo linked the Two to the oral character type: someone whose early dependency needs weren't met and who compensated by becoming the ultimate giver. The giving is a reaction formation against the unresolved hunger for love — they give what they most wish to receive." },
  { id: 645, type: 2, difficulty: 5 as 1|2|3|4|5, track1Day: 95, track2Day: 45, category: "Panel Wisdom", question: "A deeply integrated Two shares: 'I discovered that real love isn't about making myself indispensable. It's about letting people be free — even free to leave me.' This represents:", options: [{ letter: "A", text: "Detachment" }, { letter: "B", text: "The Two's ultimate growth: moving from possessive love to unconditional love that doesn't require reciprocity" }, { letter: "C", text: "Resignation" }, { letter: "D", text: "A mistyped Two" }], answer: "B", explanation: "This is the Two's highest expression: love without strings. When the Two can love without needing anything back — including the guarantee of continued connection — they've transcended their ego structure and accessed genuine, selfless love." },
  { id: 646, type: 2, difficulty: 5 as 1|2|3|4|5, track1Day: 96, track2Day: 46, category: "Historical Enneagram", question: "At Riso-Hudson Level 1 (healthiest), the Two becomes:", options: [{ letter: "A", text: "The most generous helper" }, { letter: "B", text: "The 'Disinterested Altruist' — genuinely unconditional in their love, with deep humility and the ability to nurture without needing reciprocity" }, { letter: "C", text: "A spiritual teacher" }, { letter: "D", text: "A successful leader" }], answer: "B", explanation: "At Level 1, the Two's love is truly unconditional because they've reconnected with the Holy Idea (Holy Will) and no longer need to earn love. Their giving flows from abundance rather than deficit — they nurture because they're full, not because they're empty." },
  { id: 647, type: 2, difficulty: 5 as 1|2|3|4|5, track1Day: 97, track2Day: 47, category: "Ichazo Fixations", question: "What is the relationship between the Two's passion (pride) and their virtue (humility)?", options: [{ letter: "A", text: "Pride must be eliminated to achieve humility" }, { letter: "B", text: "Humility transforms pride: the Two's gift of attunement remains, but serves genuine connection rather than self-aggrandizement" }, { letter: "C", text: "They cannot coexist" }, { letter: "D", text: "Humility means having low self-esteem" }], answer: "B", explanation: "The shift from pride to humility doesn't destroy the Two's gifts — it purifies them. The same emotional intelligence that was used to manipulate for love becomes a tool for genuine service. The talent remains; the motivation transforms." },
  { id: 648, type: 2, difficulty: 5 as 1|2|3|4|5, track1Day: 98, track2Day: 48, category: "Object Relations Deep", question: "In the Enneagram's 'Harmonic Groups,' the Two belongs to the 'Positive Outlook' group. At advanced levels, how does this interact with their growth?", options: [{ letter: "A", text: "They become even more positive" }, { letter: "B", text: "Growth involves piercing the positive outlook to access genuine emotional truth — including their own pain, anger, and neediness" }, { letter: "C", text: "The positive outlook disappears" }, { letter: "D", text: "It has no effect on growth" }], answer: "B", explanation: "The Two's 'positive outlook' defense (along with 7 and 9) reframes negative experiences as positive. Growth requires the Two to stop reframing and actually feel their difficult emotions — especially the vulnerability they've hidden behind their helping persona." },
  { id: 649, type: 2, difficulty: 5 as 1|2|3|4|5, track1Day: 99, track2Day: 49, category: "Naranjo's Character Types", question: "Naranjo described the Two as having a relationship with power that is 'seductive' rather than 'aggressive.' What does this mean structurally?", options: [{ letter: "A", text: "Twos are physically seductive" }, { letter: "B", text: "Twos gain influence through emotional bonds and making others dependent, rather than through force or intimidation" }, { letter: "C", text: "Twos don't seek power" }, { letter: "D", text: "This only applies to sexual Twos" }], answer: "B", explanation: "Naranjo observed that Twos wield significant power — but through soft means. By making themselves emotionally indispensable, they gain enormous influence over others without appearing to seek power at all. This is 'seductive' power: invisible but potent." },
  { id: 650, type: 2, difficulty: 5 as 1|2|3|4|5, track1Day: 100, track2Day: 50, category: "Integration/Disintegration Chains", question: "What is the ultimate sign that a Type 2 has achieved deep integration?", options: [{ letter: "A", text: "They help more people than ever" }, { letter: "B", text: "They can sit with their own needs, ask for help without shame, and love freely without tracking whether it's reciprocated" }, { letter: "C", text: "They stop caring about others" }, { letter: "D", text: "They become completely self-sufficient" }], answer: "B", explanation: "The integrated Two has healed the split between giving and receiving. They can say 'I need you' as easily as 'I'm here for you.' Their love becomes genuinely unconditional because it no longer serves the unconscious function of preventing abandonment." },
];
